import express from 'express';
import { authenticate as auth } from '../middleware/security.js';
import { requireAdmin, requireOrganization } from '../middleware/security.js';
import ADSyncLog from '../models/ADSyncLog.js';
import { ActiveDirectoryService } from '../services/adService.js';
const router = express.Router();
// Middleware: Auth + Org + Admin required for AD operations
router.use(auth, requireOrganization, requireAdmin);
const getADConfig = (req) => {
    // TODO: Fetch from Organization model settings
    // For now verify env vars
    return {
        url: process.env.AD_URL || 'ldaps://localhost:636',
        baseDN: process.env.AD_BASE_DN || 'dc=example,dc=com',
        username: process.env.AD_USERNAME || 'admin@example.com',
        password: process.env.AD_PASSWORD || 'password',
    };
};
// GET /api/ad/status - Check AD connection
router.get('/status', async (req, res) => {
    try {
        const config = getADConfig(req);
        const adService = new ActiveDirectoryService(config);
        const connected = await adService.checkConnection();
        if (connected) {
            res.json({ status: 'connected', message: 'Successfully connected to Active Directory' });
        }
        else {
            res
                .status(503)
                .json({ status: 'disconnected', message: 'Failed to connect to Active Directory' });
        }
    }
    catch (error) {
        res.status(500).json({ error: error.message });
    }
});
// GET /api/ad/users - List AD users (live query)
router.get('/users', async (req, res) => {
    try {
        const config = getADConfig(req);
        const adService = new ActiveDirectoryService(config);
        const users = await adService.getAllUsers();
        res.json({ users, count: users.length });
    }
    catch (error) {
        res.status(500).json({ error: error.message });
    }
});
// POST /api/ad/sync - Sync AD users to MongoDB
router.post('/sync', async (req, res) => {
    try {
        const config = getADConfig(req);
        const adService = new ActiveDirectoryService(config);
        // Check connection first
        const connected = await adService.checkConnection();
        if (!connected) {
            return res.status(503).json({ error: 'Cannot sync: AD is unreachable' });
        }
        if (!req.organizationId) {
            return res.status(400).json({ error: 'Organization context missing' });
        }
        const results = await adService.syncToMongoDB(req.organizationId);
        res.json(results);
    }
    catch (error) {
        console.error('AD Sync Error:', error);
        res.status(500).json({ error: error.message });
    }
});
// GET /api/ad/logs - Get sync logs
router.get('/logs', async (req, res) => {
    try {
        const logs = await ADSyncLog.find({ organizationId: req.organizationId })
            .sort({ createdAt: -1 })
            .limit(50);
        res.json({ logs });
    }
    catch (error) {
        res.status(500).json({ error: error.message });
    }
});
export default router;

import { Router } from 'express';
import { OAuth2Client } from 'google-auth-library';
import jwt from 'jsonwebtoken';
import { User } from '../models/User.js';
const router = Router();
const client = new OAuth2Client(process.env.GOOGLE_CLIENT_ID);
/**
 * @route   POST /api/auth/google
 * @desc    Authenticate user with Google OAuth
 * @access  Public
 */
router.post('/google', async (req, res, next) => {
    try {
        const { credential } = req.body;
        if (!credential) {
            return res.status(400).json({
                success: false,
                message: 'Google credential is required',
            });
        }
        // Verify Google token
        const ticket = await client.verifyIdToken({
            idToken: credential,
            audience: process.env.GOOGLE_CLIENT_ID,
        });
        const payload = ticket.getPayload();
        if (!payload) {
            return res.status(401).json({
                success: false,
                message: 'Invalid Google token',
            });
        }
        const { email, name, picture, sub: googleId } = payload;
        // Check if user exists
        let user = await User.findOne({ email });
        if (!user) {
            // Create new user
            user = await User.create({
                name: name || 'Google User',
                email,
                googleId,
                avatar: picture,
                role: 'citizen', // Default role for Google sign-ups
                isEmailVerified: true, // Google emails are verified
                authProvider: 'google',
            });
        }
        else {
            // Update existing user with Google info if not set
            if (!user.googleId) {
                user.googleId = googleId;
                user.isEmailVerified = true;
                user.authProvider = 'google';
                if (picture && !user.avatar) {
                    user.avatar = picture;
                }
                await user.save();
            }
        }
        // Generate JWT token
        const token = jwt.sign({ id: user._id, email: user.email, role: user.role }, process.env.JWT_SECRET || 'fallback_secret', { expiresIn: process.env.JWT_EXPIRE || '7d' });
        res.status(200).json({
            success: true,
            accessToken: token,
            user: {
                id: user._id,
                name: user.name,
                email: user.email,
                role: user.role,
                avatar: user.avatar,
            },
        });
    }
    catch (error) {
        console.error('Google OAuth error:', error);
        res.status(500).json({
            success: false,
            message: 'Google authentication failed',
            error: error.message,
        });
    }
});
export default router;

import express from 'express';
import { authenticate as auth } from '../middleware/security.js';
import { requireAdmin, requireOrganization } from '../middleware/security.js';
import NetworkDevice from '../models/NetworkDevice.js';
import defaultNetworkService from '../services/networkService.js';
const router = express.Router();
// Middleware: Auth + Org required
router.use(auth, requireOrganization);
// POST /api/monitoring/scan - Scan a subnet for active hosts
router.post('/scan', requireAdmin, async (req, res) => {
    try {
        const { subnet } = req.body; // e.g., "192.168.1"
        if (!subnet || !/^\d{1,3}\.\d{1,3}\.\d{1,3}$/.test(subnet)) {
            return res
                .status(400)
                .json({ error: 'Invalid subnet format. Use "xxx.xxx.xxx" (e.g., 192.168.1)' });
        }
        // Launch scan (this might take time, consider async job later)
        const scanResults = await defaultNetworkService.scanSubnet(subnet);
        // Enrich results with SNMP info (optional, or separate step)
        // For now, return basic ping results
        res.json({
            subnet,
            hostsFound: scanResults.length,
            results: scanResults,
        });
    }
    catch (error) {
        console.error('Scan failed:', error);
        res.status(500).json({ error: error.message });
    }
});
// GET /api/monitoring/device/:id/check - Quick check connection & SNMP
router.get('/device/:id/check', async (req, res) => {
    try {
        const device = await NetworkDevice.findOne({
            _id: req.params.id,
            organizationId: req.organizationId,
        });
        if (!device) {
            return res.status(404).json({ error: 'Device not found' });
        }
        // Check Ping
        const pingRes = await defaultNetworkService.pingHost(device.ipAddress);
        // Check SNMP if reachable
        let snmpData = {};
        if (pingRes.alive) {
            // Use community string from device config or default
            const service = new (require('../services/networkService.js').NetworkService)(device.snmpCommunity || process.env.SNMP_COMMUNITY || 'public');
            snmpData = await service.getSnmpSystemInfo(device.ipAddress);
        }
        res.json({
            device: {
                id: device._id,
                name: device.name,
                ip: device.ipAddress,
            },
            status: {
                reachable: pingRes.alive,
                responseTime: pingRes.time,
                snmp: snmpData,
            },
        });
    }
    catch (error) {
        console.error('Device check failed:', error);
        res.status(500).json({ error: error.message });
    }
});
// POST /api/monitoring/device/:id/discover - Deep Discovery & Update
router.post('/device/:id/discover', requireAdmin, async (req, res) => {
    try {
        const device = await NetworkDevice.findOne({
            _id: req.params.id,
            organizationId: req.organizationId,
        });
        if (!device) {
            return res.status(404).json({ error: 'Device not found' });
        }
        const service = new (require('../services/networkService.js').NetworkService)(device.snmpCommunity || process.env.SNMP_COMMUNITY || 'public');
        // Full SNMP Walk (simulated via getSnmpSystemInfo for now)
        const snmpData = await service.getSnmpSystemInfo(device.ipAddress);
        // Update Device Info
        if (snmpData) {
            if (snmpData.sysName)
                device.name = snmpData.sysName;
            if (snmpData.sysLocation)
                device.location = snmpData.sysLocation;
            // Update metrics
            if (snmpData.sysUpTime) {
                // Initialize currentMetrics if missing
                if (!device.currentMetrics)
                    device.currentMetrics = {
                        cpuUsage: 0,
                        memoryUsage: 0,
                        isOnline: true,
                        lastChecked: new Date(),
                        uptime: snmpData.sysUpTime ? Math.floor(snmpData.sysUpTime / 100) : 0,
                    };
                device.currentMetrics.isOnline = true;
                device.currentMetrics.lastChecked = new Date();
                // CPU/Memory would require specific MIB OIDs per vendor
            }
            await device.save();
        }
        res.json({ message: 'Device discovered and updated', data: snmpData });
    }
    catch (error) {
        res.status(500).json({ error: error.message });
    }
});
export default router;

import express from 'express';
import { requireOrganization } from '../middleware/organization';
import { authenticate as auth } from '../middleware/security.js';
import NetworkDevice from '../models/NetworkDevice';
const router = express.Router();
// Apply authentication and organization context to all routes
router.use(auth, requireOrganization);
// GET /api/network/devices - Get all network devices
router.get('/devices', async (req, res) => {
    try {
        const { type, status, search } = req.query;
        const query = { organizationId: req.organizationId };
        if (type)
            query.type = type;
        if (search) {
            query.$or = [
                { name: new RegExp(search, 'i') },
                { hostname: new RegExp(search, 'i') },
                { ipAddress: new RegExp(search, 'i') },
            ];
        }
        const devices = await NetworkDevice.find(query).sort({ name: 1 });
        res.json({ devices, count: devices.length });
    }
    catch (error) {
        console.error('Error fetching network devices:', error);
        res.status(500).json({ error: error.message });
    }
});
// GET /api/network/devices/:id - Get single device
router.get('/devices/:id', async (req, res) => {
    try {
        const device = await NetworkDevice.findOne({
            _id: req.params.id,
            organizationId: req.organizationId,
        });
        if (!device) {
            return res.status(404).json({ error: 'Device not found' });
        }
        res.json({ device });
    }
    catch (error) {
        console.error('Error fetching device:', error);
        res.status(500).json({ error: error.message });
    }
});
// POST /api/network/devices - Create new device
router.post('/devices', async (req, res) => {
    try {
        const device = await NetworkDevice.create({
            ...req.body,
            organizationId: req.organizationId,
        });
        res.status(201).json({ device });
    }
    catch (error) {
        console.error('Error creating device:', error);
        res.status(500).json({ error: error.message });
    }
});
// PUT /api/network/devices/:id - Update device
router.put('/devices/:id', async (req, res) => {
    try {
        const device = await NetworkDevice.findOneAndUpdate({ _id: req.params.id, organizationId: req.organizationId }, { $set: req.body }, { new: true, runValidators: true });
        if (!device) {
            return res.status(404).json({ error: 'Device not found' });
        }
        res.json({ device });
    }
    catch (error) {
        console.error('Error updating device:', error);
        res.status(500).json({ error: error.message });
    }
});
// DELETE /api/network/devices/:id - Delete device
router.delete('/devices/:id', async (req, res) => {
    try {
        const device = await NetworkDevice.findOneAndDelete({
            _id: req.params.id,
            organizationId: req.organizationId,
        });
        if (!device) {
            return res.status(404).json({ error: 'Device not found' });
        }
        res.json({ message: 'Device deleted successfully', device });
    }
    catch (error) {
        console.error('Error deleting device:', error);
        res.status(500).json({ error: error.message });
    }
});
// GET /api/network/devices/:id/metrics - Get device metrics
router.get('/devices/:id/metrics', async (req, res) => {
    try {
        const device = await NetworkDevice.findOne({
            _id: req.params.id,
            organizationId: req.organizationId,
        });
        if (!device) {
            return res.status(404).json({ error: 'Device not found' });
        }
        // Return current metrics
        const metrics = {
            device: {
                id: device._id,
                name: device.name,
                ipAddress: device.ipAddress,
            },
            current: device.currentMetrics || {},
            interfaces: device.interfaces || [],
            timestamp: new Date(),
        };
        res.json({ metrics });
    }
    catch (error) {
        console.error('Error fetching device metrics:', error);
        res.status(500).json({ error: error.message });
    }
});
// POST /api/network/devices/:id/metrics - Update device metrics (from monitoring service)
router.post('/devices/:id/metrics', async (req, res) => {
    try {
        const device = await NetworkDevice.findOneAndUpdate({ _id: req.params.id, organizationId: req.organizationId }, {
            $set: {
                currentMetrics: {
                    ...req.body,
                    lastChecked: new Date(),
                },
            },
        }, { new: true });
        if (!device) {
            return res.status(404).json({ error: 'Device not found' });
        }
        res.json({ device });
    }
    catch (error) {
        console.error('Error updating device metrics:', error);
        res.status(500).json({ error: error.message });
    }
});
// GET /api/network/stats - Get network statistics
router.get('/stats', async (req, res) => {
    try {
        const stats = {
            total: await NetworkDevice.countDocuments({ organizationId: req.organizationId }),
            byType: await NetworkDevice.aggregate([
                { $match: { organizationId: req.organizationId } },
                { $group: { _id: '$type', count: { $sum: 1 } } },
            ]),
            online: await NetworkDevice.countDocuments({
                organizationId: req.organizationId,
                'currentMetrics.isOnline': true,
            }),
            offline: await NetworkDevice.countDocuments({
                organizationId: req.organizationId,
                'currentMetrics.isOnline': false,
            }),
            highCPU: await NetworkDevice.countDocuments({
                organizationId: req.organizationId,
                'currentMetrics.cpuUsage': { $gte: 80 },
            }),
            highMemory: await NetworkDevice.countDocuments({
                organizationId: req.organizationId,
                'currentMetrics.memoryUsage': { $gte: 80 },
            }),
        };
        res.json({ stats });
    }
    catch (error) {
        console.error('Error fetching network stats:', error);
        res.status(500).json({ error: error.message });
    }
});
export default router;

import { Router } from 'express';
import { body } from 'express-validator';
import { authenticate, requireOrganization } from '../middleware/security.js';
import { validator } from '../middleware/validator.js';
import AuditLog from '../models/AuditLog.js';
import { Membership } from '../models/Membership.js';
import { Organization } from '../models/Organization.js';
const router = Router();
/**
 * @route   POST /api/organizations
 * @desc    Create a new organization
 * @access  Private
 */
router.post('/', authenticate, [
    body('name').notEmpty().trim().isLength({ min: 3, max: 100 }),
    body('slug')
        .notEmpty()
        .trim()
        .isLength({ min: 3, max: 50 })
        .matches(/^[a-z0-9-]+$/),
], validator, async (req, res) => {
    try {
        const { name, slug } = req.body;
        const userId = req.user.id;
        // Check if slug already exists
        const existing = await Organization.findOne({ slug });
        if (existing) {
            return res.status(409).json({ message: 'Ce slug est déjà utilisé' });
        }
        // Create organization
        const organization = await Organization.create({
            name,
            slug,
            ownerId: userId,
            subscription: {
                plan: 'FREE',
                status: 'TRIAL',
                maxUsers: 5,
                maxTickets: 100,
                // Trial expires in 14 days
                expiresAt: new Date(Date.now() + 14 * 24 * 60 * 60 * 1000),
            },
        });
        // Create membership for the creator (OWNER role)
        await Membership.create({
            userId,
            organizationId: organization._id,
            roles: ['OWNER'],
            status: 'ACTIVE',
        });
        // Audit log
        await AuditLog.create({
            action: 'CREATE_ORGANIZATION',
            userId,
            targetId: organization._id.toString(),
            targetType: 'Organization',
            details: { name, slug },
            ipAddress: req.ip,
        });
        res.status(201).json({
            success: true,
            organization,
        });
    }
    catch (error) {
        res.status(500).json({ message: error.message });
    }
});
/**
 * @route   GET /api/organizations
 * @desc    Get all organizations the user is a member of
 * @access  Private
 */
router.get('/', authenticate, async (req, res) => {
    try {
        const userId = req.user.id;
        // Find all memberships for this user
        const memberships = await Membership.find({
            userId,
            status: 'ACTIVE',
        }).populate('organizationId');
        const organizations = memberships
            .filter((m) => m.organizationId) // Guard against null populates
            .map((m) => ({
            ...m.organizationId.toObject(),
            membership: {
                roles: m.roles,
                joinedAt: m.joinedAt,
            },
        }));
        res.json({ success: true, organizations });
    }
    catch (error) {
        res.status(500).json({ message: error.message });
    }
});
/**
 * @route   GET /api/organizations/:id
 * @desc    Get organization details
 * @access  Private (must be a member)
 */
router.get('/:id', authenticate, requireOrganization, async (req, res) => {
    try {
        const organization = await Organization.findById(req.organizationId);
        if (!organization) {
            return res.status(404).json({ message: 'Organisation introuvable' });
        }
        res.json({
            success: true,
            organization,
            membership: {
                roles: req.membership.roles,
                joinedAt: req.membership.joinedAt,
            },
        });
    }
    catch (error) {
        res.status(500).json({ message: error.message });
    }
});
/**
 * @route   PATCH /api/organizations/:id
 * @desc    Update organization settings
 * @access  Private (Admin only)
 */
router.patch('/:id', authenticate, requireOrganization, async (req, res) => {
    try {
        const userId = req.user.id;
        // Check admin permission
        if (!req.membership.isAdmin()) {
            return res.status(403).json({ message: 'Droits insuffisants' });
        }
        const organization = await Organization.findByIdAndUpdate(req.organizationId, { $set: req.body }, { new: true, runValidators: true });
        if (!organization) {
            return res.status(404).json({ message: 'Organisation introuvable' });
        }
        res.json({ success: true, organization });
    }
    catch (error) {
        res.status(500).json({ message: error.message });
    }
});
export default router;

import { Router } from 'express';
import { authenticate, requireOrganization } from '../middleware/security.js';
import { Leave } from '../models/Leave.js';
import { Roster } from '../models/Roster.js';
const router = Router();
router.get('/', authenticate, requireOrganization, async (req, res, next) => {
    try {
        const { week } = req.query;
        const filter = { week, organizationId: req.organizationId };
        const roster = await Roster.findOne(filter).populate('shifts.staffId');
        if (!roster) {
            return res.json({ week, shifts: [] });
        }
        res.json(roster);
    }
    catch (err) {
        next(err);
    }
});
router.post('/update', authenticate, requireOrganization, async (req, res, next) => {
    try {
        const { week, shifts } = req.body;
        const organizationId = req.organizationId;
        // Simple validation: Check for leaves
        const staffIds = shifts.map((s) => s.staffId);
        const activeLeaves = await Leave.find({
            staffId: { $in: staffIds },
            status: 'Approved',
            organizationId,
        });
        const roster = await Roster.findOneAndUpdate({ week, organizationId }, { week, shifts, organizationId }, { upsert: true, new: true });
        res.json(roster);
    }
    catch (err) {
        next(err);
    }
});
router.delete('/shifts/:shiftId', authenticate, requireOrganization, async (req, res, next) => {
    try {
        const { week } = req.body;
        const organizationId = req.organizationId;
        const roster = await Roster.findOneAndUpdate({ week, organizationId }, { $pull: { shifts: { _id: req.params.shiftId } } }, { new: true });
        res.json(roster);
    }
    catch (err) {
        next(err);
    }
});
export default router;

import axios from 'axios';
import { performance } from 'perf_hooks';
const API_URL = process.env.API_URL || 'http://localhost:5001';
const FRONTEND_URL = process.env.FRONTEND_URL || 'http://localhost:3000';
const results = [];
function addResult(service, metric, value, unit, thresholds) {
    let status = 'good';
    if (value > thresholds.warning)
        status = 'critical';
    else if (value > thresholds.good)
        status = 'warning';
    results.push({ service, metric, value, unit, status });
}
async function measureApiEndpoint(name, url) {
    try {
        const start = performance.now();
        const response = await axios.get(url, { timeout: 5000 });
        const end = performance.now();
        const duration = end - start;
        addResult('API', `${name} - Response Time`, duration, 'ms', { good: 100, warning: 300 });
        if (response.headers['content-length']) {
            const size = parseInt(response.headers['content-length']) / 1024;
            addResult('API', `${name} - Payload Size`, size, 'KB', { good: 50, warning: 200 });
        }
    }
    catch (error) {
        console.error(`❌ Failed to test ${name}:`, error.message);
        results.push({ service: 'API', metric: `${name} - Availability`, value: 0, unit: 'available', status: 'critical' });
    }
}
async function testDatabasePerformance() {
    // Test endpoints that don't require authentication for initial diagnostic
    console.log('Testing API endpoints...');
    // Health check (no auth required)
    try {
        const start = performance.now();
        await axios.get(`${API_URL}/`);
        const end = performance.now();
        addResult('API', 'Health Check', end - start, 'ms', { good: 50, warning: 150 });
    }
    catch (error) {
        results.push({ service: 'API', metric: 'Health Check', value: 0, unit: 'available', status: 'critical' });
    }
}
async function testFrontendMetrics() {
    try {
        const start = performance.now();
        const response = await axios.get(FRONTEND_URL, { timeout: 10000 });
        const end = performance.now();
        const duration = end - start;
        addResult('Frontend', 'Initial Load Time', duration, 'ms', { good: 500, warning: 1500 });
        if (response.headers['content-length']) {
            const size = parseInt(response.headers['content-length']) / 1024;
            addResult('Frontend', 'HTML Size', size, 'KB', { good: 100, warning: 300 });
        }
    }
    catch (error) {
        console.error('❌ Frontend test failed:', error.message);
        results.push({ service: 'Frontend', metric: 'Availability', value: 0, unit: 'available', status: 'critical' });
    }
}
function printResults() {
    console.log('\n=====================================');
    console.log('🔍 DIAGNOSTIC DE PERFORMANCE');
    console.log('=====================================\n');
    const serviceGroups = results.reduce((acc, result) => {
        if (!acc[result.service])
            acc[result.service] = [];
        acc[result.service].push(result);
        return acc;
    }, {});
    for (const [service, metrics] of Object.entries(serviceGroups)) {
        console.log(`\n📊 ${service.toUpperCase()}`);
        console.log('─'.repeat(50));
        metrics.forEach(metric => {
            const icon = metric.status === 'good' ? '✅' : metric.status === 'warning' ? '⚠️' : '❌';
            console.log(`${icon} ${metric.metric}: ${metric.value.toFixed(2)} ${metric.unit}`);
        });
    }
    // Summary
    const good = results.filter(r => r.status === 'good').length;
    const warning = results.filter(r => r.status === 'warning').length;
    const critical = results.filter(r => r.status === 'critical').length;
    console.log('\n=====================================');
    console.log('RÉSUMÉ');
    console.log('=====================================');
    console.log(`✅ Bon: ${good}`);
    console.log(`⚠️ Attention: ${warning}`);
    console.log(`❌ Critique: ${critical}`);
    console.log(`Total: ${results.length} métriques testées\n`);
}
