import ActiveDirectory from 'activedirectory2';
import ADSyncLog from '../models/ADSyncLog.js';
import { Membership } from '../models/Membership.js';
import { User } from '../models/User.js';
export class ActiveDirectoryService {
    ad;
    ldapClient;
    config;
    constructor(config) {
        this.config = config;
        // Initialize ActiveDirectory library for easier querying
        this.ad = new ActiveDirectory({
            url: config.url,
            baseDN: config.baseDN,
            username: config.username,
            password: config.password,
            attributes: {
                user: [
                    'cn',
                    'sAMAccountName',
                    'mail',
                    'memberOf',
                    'telephoneNumber',
                    'givenName',
                    'sn',
                    'userPrincipalName',
                ],
                group: ['cn', 'description'],
            },
        });
    }
    // Check connection
    async checkConnection() {
        return new Promise((resolve) => {
            this.ad.findUser(this.config.username, (err) => {
                if (err) {
                    console.error('AD Connection Check Failed:', err);
                    resolve(false);
                }
                else {
                    resolve(true);
                }
            });
        });
    }
    // Authenticate user
    async authenticateUser(username, password) {
        return new Promise((resolve, reject) => {
            this.ad.authenticate(username, password, (err, auth) => {
                if (err) {
                    console.error('AD Auth Error:', err);
                    resolve(false);
                    return;
                }
                resolve(auth);
            });
        });
    }
    // Get all users
    async getAllUsers() {
        return new Promise((resolve, reject) => {
            const query = '(&(objectClass=user)(!(userAccountControl:1.2.840.113556.1.4.803:=2)))'; // Enable users only
            this.ad.findUsers(query, (err, users) => {
                if (err)
                    reject(err);
                resolve(users || []);
            });
        });
    }
    // Get user by username
    async getUserByUsername(username) {
        return new Promise((resolve, reject) => {
            this.ad.findUser(username, (err, user) => {
                if (err)
                    reject(err);
                resolve(user || null);
            });
        });
    }
    // Get user groups
    async getUserGroups(username) {
        return new Promise((resolve, reject) => {
            this.ad.getGroupMembershipForUser(username, (err, groups) => {
                if (err)
                    reject(err);
                resolve(groups?.map((g) => g.cn) || []);
            });
        });
    }
    // Sync users to MongoDB
    async syncToMongoDB(organizationId) {
        const results = { imported: 0, updated: 0, errors: [] };
        let users = [];
        try {
            users = await this.getAllUsers();
        }
        catch (error) {
            console.error('Failed to fetch users from AD:', error);
            throw new Error('Failed to fetch users from AD: ' + error.message);
        }
        const startTime = Date.now();
        for (const adUser of users) {
            try {
                if (!adUser.sAMAccountName)
                    continue;
                const groups = await this.getUserGroups(adUser.sAMAccountName);
                const role = this.mapGroupsToRole(groups);
                // Ensure email exists or create a fake one based on usage
                const email = adUser.mail || `${adUser.sAMAccountName}@reclamtrack.local`.toLowerCase();
                // Check if user exists
                const existingUser = await User.findOne({
                    $or: [{ email: email }, { adUsername: adUser.sAMAccountName }],
                });
                if (existingUser) {
                    // Update
                    await User.findByIdAndUpdate(existingUser._id, {
                        firstName: adUser.givenName || adUser.cn.split(' ')[0],
                        lastName: adUser.sn || adUser.cn.split(' ').slice(1).join(' '),
                        phone: adUser.telephoneNumber,
                        adSyncedAt: new Date(),
                        adGroups: groups,
                    });
                    // Ensure membership exists
                    const membership = await Membership.findOne({
                        userId: existingUser._id,
                        organizationId,
                    });
                    if (!membership) {
                        await Membership.create({
                            userId: existingUser._id,
                            organizationId,
                            roles: [role],
                            status: 'active',
                        });
                    }
                    else if (!membership.roles || !membership.roles.includes(role)) {
                        // Update role if changed in AD
                        // Note: Usually we might want to manually manage keys, but let's sync for now
                        // await Membership.findByIdAndUpdate(membership._id, { roles: [role] });
                    }
                    results.updated++;
                }
                else {
                    // Create new User
                    const newUser = await User.create({
                        email,
                        password: 'AD_AUTH_USER', // Placeholder, they authenticate against AD
                        firstName: adUser.givenName || adUser.cn.split(' ')[0],
                        lastName: adUser.sn || adUser.cn.split(' ').slice(1).join(' ') || 'User',
                        phone: adUser.telephoneNumber,
                        role,
                        adUsername: adUser.sAMAccountName,
                        adSyncedAt: new Date(),
                        adGroups: groups,
                        authMethod: 'ad',
                        isVerified: true,
                    });
                    // Create membership
                    await Membership.create({
                        userId: newUser._id,
                        organizationId,
                        roles: [role],
                        status: 'active',
                    });
                    results.imported++;
                }
            }
            catch (error) {
                results.errors.push({
                    username: adUser.sAMAccountName,
                    error: error.message,
                });
            }
        }
        // Log sync
        await ADSyncLog.create({
            organizationId,
            syncType: 'manual',
            action: results.errors.length > 0 ? 'error' : 'imported',
            totalProcessed: users.length,
            successful: results.imported + results.updated,
            failed: results.errors.length,
            changes: {
                imported: results.imported,
                updated: results.updated,
                disabled: 0,
            },
            duration: Date.now() - startTime,
            syncErrors: results.errors,
        });
        return results;
    }
    // Map AD groups to ReclamTrack roles
    mapGroupsToRole(groups) {
        const normalizedGroups = groups.map((g) => g.toLowerCase());
        if (normalizedGroups.some((g) => g.includes('admin') || g.includes('domain admins'))) {
            return 'admin';
        }
        else if (normalizedGroups.some((g) => g.includes('manager'))) {
            return 'manager';
        }
        else if (normalizedGroups.some((g) => g.includes('support') || g.includes('agent'))) {
            return 'agent';
        }
        else {
            return 'citizen'; // default role
        }
    }
}
export default ActiveDirectoryService;

import { Types } from 'mongoose';
import { Complaint } from '../models/Complaint.js';
import { Team } from '../models/Team.js';
import { autoAssignComplaint } from './schedulingService.js';
import notificationService from './socketService.js';
export class ComplaintService {
    /**
     * Get all complaints with optional filters
     */
    async getAllComplaints(filters = {}, organizationId) {
        const query = { organizationId };
        if (filters.status) {
            query.status = filters.status;
        }
        if (filters.priority) {
            query.priority = filters.priority;
        }
        if (filters.category) {
            query.category = filters.category;
        }
        if (filters.assignedTeamId) {
            query.assignedTeamId = new Types.ObjectId(filters.assignedTeamId);
        }
        const complaints = await Complaint.find(query)
            .populate('assignedTeamId', 'name specialization')
            .populate('technicianId', 'firstName lastName email')
            .sort({ createdAt: -1 });
        return complaints;
    }
    /**
     * Get a single complaint by ID
     */
    async getComplaintById(id, organizationId) {
        if (!Types.ObjectId.isValid(id)) {
            throw new Error('Invalid complaint ID');
        }
        const complaint = await Complaint.findOne({ _id: id, organizationId })
            .populate('assignedTeamId', 'name specialization')
            .populate('technicianId', 'firstName lastName email');
        if (!complaint) {
            throw new Error('Complaint not found');
        }
        return complaint;
    }
    /**
     * Create a new complaint
     */
    async createComplaint(data) {
        const complaint = new Complaint(data);
        await complaint.save();
        // Auto-assign if not already assigned
        if (!complaint.assignedTeamId) {
            try {
                const teamId = await autoAssignComplaint(complaint._id.toString());
                if (teamId) {
                    complaint.assignedTeamId = teamId;
                    complaint.assignedAt = new Date();
                    complaint.status = 'nouvelle'; // Or 'assigned' if we want to change status immediately
                    // But autoAssignComplaint already updates the DB document!
                    // We need to reload the complaint or just trust the side effect.
                    // autoAssignComplaint updates the doc in DB.
                    // Let's refresh our local instance or manually update it to match.
                    // autoAssignComplaint returns Promise<Types.ObjectId | null>
                }
            }
            catch (error) {
                console.error('Error in auto-scheduling:', error);
            }
        }
        // Trigger notifications if assigned (either manually or via auto-schedule)
        // We need to re-fetch to get the latest state including auto-assignment updates if any
        const updatedComplaint = await Complaint.findById(complaint._id).populate('assignedTeamId', 'name specialization');
        if (updatedComplaint?.assignedTeamId) {
            try {
                const teamId = updatedComplaint.assignedTeamId._id
                    ? updatedComplaint.assignedTeamId._id.toString()
                    : updatedComplaint.assignedTeamId.toString();
                // Fetch team members for persistence
                const team = await Team.findById(teamId).select('members');
                const memberIds = team?.members.map((m) => m.toString()) || [];
                await notificationService.notifyComplaintAssigned(teamId, updatedComplaint, memberIds);
            }
            catch (error) {
                console.error('Failed to send team notification:', error);
            }
        }
        // Notify technician if assigned
        if (updatedComplaint?.technicianId) {
            try {
                const techId = updatedComplaint.technicianId._id
                    ? updatedComplaint.technicianId._id.toString()
                    : updatedComplaint.technicianId.toString();
                await notificationService.sendToUser(techId, {
                    type: 'complaint_assigned',
                    title: 'Nouvelle Réclamation Assignée',
                    message: `La réclamation "${updatedComplaint.title}" vous a été assignée directement.`,
                    data: { complaintId: updatedComplaint._id },
                });
            }
            catch (error) {
                console.error('Failed to send technician notification:', error);
            }
        }
        return updatedComplaint || complaint;
    }
    /**
     * Update a complaint
     */
    async updateComplaint(id, data, organizationId) {
        if (!Types.ObjectId.isValid(id)) {
            throw new Error('Invalid complaint ID');
        }
        const complaint = await Complaint.findOneAndUpdate({ _id: id, organizationId }, { $set: data }, { new: true, runValidators: true })
            .populate('assignedTeamId', 'name specialization')
            .populate('technicianId', 'firstName lastName email');
        if (!complaint) {
            throw new Error('Complaint not found');
        }
        return complaint;
    }
    /**
     * Delete a complaint
     */
    async deleteComplaint(id, organizationId) {
        if (!Types.ObjectId.isValid(id)) {
            throw new Error('Invalid complaint ID');
        }
        const complaint = await Complaint.findOneAndDelete({ _id: id, organizationId });
        if (!complaint) {
            throw new Error('Complaint not found');
        }
        return complaint;
    }
    /**
     * Get complaint statistics
     */
    async getComplaintStats(organizationId) {
        const total = await Complaint.countDocuments({ organizationId });
        const byStatus = await Complaint.aggregate([
            { $match: { organizationId: new Types.ObjectId(organizationId) } },
            { $group: { _id: '$status', count: { $sum: 1 } } },
        ]);
        const byPriority = await Complaint.aggregate([
            { $match: { organizationId: new Types.ObjectId(organizationId) } },
            { $group: { _id: '$priority', count: { $sum: 1 } } },
        ]);
        return {
            total,
            byStatus: byStatus.reduce((acc, item) => {
                acc[item._id] = item.count;
                return acc;
            }, {}),
            byPriority: byPriority.reduce((acc, item) => {
                acc[item._id] = item.count;
                return acc;
            }, {}),
        };
    }
    /**
     * Approve a complaint (change status to 'en cours')
     */
    async approveComplaint(id, organizationId, approvedBy) {
        if (!Types.ObjectId.isValid(id)) {
            throw new Error('Invalid complaint ID');
        }
        const complaint = await Complaint.findOne({ _id: id, organizationId });
        if (!complaint) {
            throw new Error('Complaint not found');
        }
        if (complaint.status !== 'nouvelle') {
            throw new Error('Only new complaints can be approved');
        }
        complaint.status = 'en cours';
        await complaint.save();
        // Populate for return
        await complaint.populate('assignedTeamId', 'name specialization');
        await complaint.populate('technicianId', 'firstName lastName email');
        // Send notification if assigned
        if (complaint.assignedTeamId) {
            try {
                const teamId = complaint.assignedTeamId._id
                    ? complaint.assignedTeamId._id.toString()
                    : complaint.assignedTeamId.toString();
                const team = await Team.findById(teamId).select('members');
                const memberIds = team?.members.map((m) => m.toString()) || [];
                await notificationService.notifyComplaintAssigned(teamId, complaint, memberIds);
            }
            catch (error) {
                console.error('Failed to send notification:', error);
            }
        }
        if (complaint.technicianId) {
            try {
                const techId = complaint.technicianId._id
                    ? complaint.technicianId._id.toString()
                    : complaint.technicianId.toString();
                await notificationService.sendToUser(techId, {
                    type: 'complaint_assigned',
                    title: 'Réclamation Approuvée et Assignée',
                    message: `La réclamation "${complaint.title}" a été approuvée et vous est assignée.`,
                    data: { complaintId: complaint._id },
                });
            }
            catch (error) {
                console.error('Failed to send technician notification:', error);
            }
        }
        return complaint;
    }
    /**
     * Reject a complaint
     */
    async rejectComplaint(id, organizationId, rejectionReason, rejectedBy) {
        if (!Types.ObjectId.isValid(id)) {
            throw new Error('Invalid complaint ID');
        }
        if (!rejectionReason || rejectionReason.trim().length === 0) {
            throw new Error('Rejection reason is required');
        }
        const complaint = await Complaint.findOne({ _id: id, organizationId });
        if (!complaint) {
            throw new Error('Complaint not found');
        }
        if (complaint.status !== 'nouvelle') {
            throw new Error('Only new complaints can be rejected');
        }
        complaint.status = 'rejetée';
        complaint.rejectionReason = rejectionReason;
        await complaint.save();
        // Populate for return
        await complaint.populate('assignedTeamId', 'name specialization');
        await complaint.populate('technicianId', 'firstName lastName email');
        return complaint;
    }
}
export const complaintService = new ComplaintService();

import snmp from 'snmp-native';
import ping from 'ping';
export class NetworkService {
    community;
    constructor(community = 'public') {
        this.community = community;
    }
    // Check if a host is reachable via Ping
    async pingHost(host) {
        try {
            const res = await ping.promise.probe(host, { timeout: 2 });
            return { alive: res.alive, time: typeof res.time === 'number' ? res.time : undefined };
        }
        catch (error) {
            console.error(`Ping failed for ${host}:`, error);
            return { alive: false };
        }
    }
    // Scan a subnet (simplistic sequential scan for now, could be parallelized)
    async scanSubnet(subnet) {
        const results = [];
        const parts = subnet.split('.');
        if (parts.length !== 3) { // Expecting "192.168.1"
            throw new Error('Invalid subnet format. Expected format: "xxx.xxx.xxx"');
        }
        const baseIp = subnet;
        // Create an array of promises for parallel execution (batch of 255)
        const scanPromises = [];
        for (let i = 1; i < 255; i++) {
            const ip = `${baseIp}.${i}`;
            scanPromises.push(this.pingHost(ip).then(res => ({ ip, ...res })));
        }
        const scanResults = await Promise.all(scanPromises);
        return scanResults
            .filter(r => r.alive)
            .map(r => ({
            ip: r.ip,
            isAlive: true,
            responseTime: r.time
        }));
    }
    // Get basic SNMP info (System Group)
    async getSnmpSystemInfo(host) {
        return new Promise((resolve, reject) => {
            const session = new snmp.Session({ host, community: this.community });
            const oids = [
                [1, 3, 6, 1, 2, 1, 1, 1, 0], // sysDescr
                [1, 3, 6, 1, 2, 1, 1, 3, 0], // sysUpTime
                [1, 3, 6, 1, 2, 1, 1, 4, 0], // sysContact
                [1, 3, 6, 1, 2, 1, 1, 5, 0], // sysName
                [1, 3, 6, 1, 2, 1, 1, 6, 0], // sysLocation
                [1, 3, 6, 1, 2, 1, 2, 1, 0], // ifNumber
            ];
            session.getAll({ oids }, (error, varbinds) => {
                if (error) {
                    session.close();
                    // Don't reject, just return empty/partial data as SNMP might fail or timeout
                    console.warn(`SNMP failed for ${host}:`, error);
                    resolve({});
                    return;
                }
                const metrics = {};
                varbinds.forEach(vb => {
                    const oidStr = vb.oid.join('.'); // Convert OID array to string for checking
                    // Mapping based on standard OIDs (simplified)
                    if (this.compareOid(vb.oid, [1, 3, 6, 1, 2, 1, 1, 1, 0]))
                        metrics.sysDescr = vb.value;
                    if (this.compareOid(vb.oid, [1, 3, 6, 1, 2, 1, 1, 3, 0]))
                        metrics.sysUpTime = vb.value;
                    if (this.compareOid(vb.oid, [1, 3, 6, 1, 2, 1, 1, 4, 0]))
                        metrics.sysContact = vb.value;
                    if (this.compareOid(vb.oid, [1, 3, 6, 1, 2, 1, 1, 5, 0]))
                        metrics.sysName = vb.value;
                    if (this.compareOid(vb.oid, [1, 3, 6, 1, 2, 1, 1, 6, 0]))
                        metrics.sysLocation = vb.value;
                    if (this.compareOid(vb.oid, [1, 3, 6, 1, 2, 1, 2, 1, 0]))
                        metrics.interfaces = vb.value;
                });
                session.close();
                resolve(metrics);
            });
        });
    }
    // Helper to compare OID arrays
    compareOid(oid1, oid2) {
        if (oid1.length !== oid2.length)
            return false;
        for (let i = 0; i < oid1.length; i++) {
            if (oid1[i] !== oid2[i])
                return false;
        }
        return true;
    }
}
export default new NetworkService();

import { consumer } from '../config/kafka.js';
import { Complaint } from '../models/Complaint.js';
import { logger } from '../utils/logger.js';
export const startSagaConsumer = async () => {
    try {
        await consumer.connect();
        await consumer.subscribe({ topic: 'complaint-events', fromBeginning: false });
        await consumer.run({
            eachMessage: async ({ topic, partition, message }) => {
                const value = message.value?.toString() || '{}';
                try {
                    const payload = JSON.parse(value);
                    if (payload.type === 'COMPLAINT_ASSIGNED') {
                        logger.info(`🔄 [Saga] Backend received ASSIGNED for ${payload.complaintId}`);
                        // Update Complaint
                        await Complaint.findByIdAndUpdate(payload.complaintId, {
                            assignedTeamId: payload.teamId,
                            status: 'en cours',
                            updatedAt: new Date()
                        });
                        logger.info(`✅ [Saga] Complaint ${payload.complaintId} updated with Team ${payload.teamId}`);
                    }
                    if (payload.type === 'ASSIGNMENT_FAILED') {
                        logger.warn(`⚠️ [Saga] Backend received FAILED for ${payload.complaintId}`);
                        // Compensation: Escalate priority
                        await Complaint.findByIdAndUpdate(payload.complaintId, {
                            priority: 'urgent',
                            // status: 'rejetée'? No, keep new but urgent.
                            updatedAt: new Date()
                        });
                        logger.info(`↩️ [Saga] Complaint ${payload.complaintId} priority escalated (Compensation)`);
                    }
                }
                catch (err) {
                    logger.error('❌ [Saga] Error processing message:', err);
                }
            }
        });
        logger.info('✅ Saga Consumer started');
    }
    catch (error) {
        logger.error('❌ Failed to start Saga Consumer:', error);
    }
};

import { Server as SocketIOServer } from 'socket.io';
import { Notification } from '../models/Notification.js';
import { logger } from '../utils/logger.js';
class NotificationService {
    io = null;
    init(server) {
        this.io = new SocketIOServer(server, {
            cors: {
                origin: process.env.FRONTEND_URL || '*', // Allow all for now or specify frontend URL
                methods: ['GET', 'POST'],
            },
        });
        // Namespace principal pour les notifications
        this.io.on('connection', (socket) => {
            logger.info(`🔔 Client connecté: ${socket.id}`);
            // Authentification (optionnel mais recommandé)
            socket.on('authenticate', (token) => {
                // Ici tu peux vérifier le token JWT
                // et stocker userId dans socket.data.userId
                // socket.data.userId = 'user_' + ...;
            });
            socket.on('join-rooms', (rooms) => {
                rooms.forEach((room) => socket.join(room));
            });
            socket.on('disconnect', () => {
                logger.info(`🔌 Client déconnecté: ${socket.id}`);
            });
            // --- WebRTC Signaling for SRTP Calls ---
            socket.on('call-user', (data) => {
                logger.info(`📞 Call initiated from ${data.from} to ${data.userToCall}`);
                this.io?.to(`user:${data.userToCall}`).emit('call-made', {
                    signal: data.signalData,
                    from: data.from,
                    fromName: data.fromName,
                });
            });
            socket.on('answer-call', (data) => {
                logger.info(`📞 Call answered by ${socket.id} for ${data.to}`);
                this.io
                    ?.to(`user:${data.to}`)
                    .emit('call-answered', { signal: data.signal, from: socket.id });
            });
            socket.on('reject-call', (data) => {
                logger.info(`📞 Call rejected by ${socket.id} for ${data.to}`);
                this.io?.to(`user:${data.to}`).emit('call-rejected', { from: socket.id });
            });
            socket.on('ice-candidate', (data) => {
                this.io
                    ?.to(`user:${data.to}`)
                    .emit('ice-candidate', { candidate: data.candidate, from: socket.id });
            });
            // ---------------------------------------
        });
        // Namespace /logs pour les logs en temps réel (Enterprise DB)
        this.initLogsNamespace();
        // Namespace /scheduler pour le planning (Enterprise DB)
        this.initSchedulerNamespace();
        // Namespace /security pour la sécurité en temps réel
        this.initSecurityNamespace();
        return this.io;
    }
    /**
     * Namespace /logs pour les logs de base de données en temps réel
     */
    initLogsNamespace() {
        if (!this.io)
            return;
        const logsNamespace = this.io.of('/logs');
        const logTypes = ['INFO', 'WARN', 'ERROR', 'BACKUP'];
        const containers = ['SQL', 'API_GATEWAY', 'WORKER', 'WAF', 'AUTH', 'REPLICA_1', 'REPLICA_2'];
        function randomLog() {
            const now = new Date().toISOString().replace('T', ' ').split('.')[0];
            const type = logTypes[Math.floor(Math.random() * logTypes.length)];
            const container = containers[Math.floor(Math.random() * containers.length)];
            let message = '';
            switch (type) {
                case 'INFO':
                    message = 'Heartbeat OK – all services healthy.';
                    break;
                case 'WARN':
                    message = 'Replication lag > 100 ms on replica-2.';
                    break;
                case 'ERROR':
                    message = 'Duplicate key violation on table `complaints`.';
                    break;
                case 'BACKUP':
                    message = 'Backup #20240211-01 completed (120 GB).';
                    break;
            }
            return {
                timestamp: now,
                type,
                container,
                message,
            };
        }
        logsNamespace.on('connection', (socket) => {
            logger.info(`🔌 Client log socket connected: ${socket.id}`);
            const interval = setInterval(() => {
                socket.emit('log', randomLog());
            }, 2000);
            socket.on('disconnect', () => {
                clearInterval(interval);
                logger.info(`🔌 Client log socket disconnected: ${socket.id}`);
            });
        });
    }
    /**
     * Namespace /scheduler pour la synchronisation du planning en temps réel
     */
    initSchedulerNamespace() {
        if (!this.io)
            return;
        const schedulerNamespace = this.io.of('/scheduler');
        const personnel = [
            'Alex Henderson',
            'Sarah Jenkins',
            'Marcus Vane',
            'Dave Miller',
            'Elena Rodriguez',
        ];
        const statuses = ['online', 'break', 'offline', 'busy'];
        function getRandomStatusUpdate() {
            const person = personnel[Math.floor(Math.random() * personnel.length)];
            const status = statuses[Math.floor(Math.random() * statuses.length)];
            return {
                type: 'PERSONNEL_UPDATE',
                data: { name: person, status },
            };
        }
        function getRandomOrder() {
            const id = Math.floor(1000 + Math.random() * 9000);
            return {
                type: 'NEW_ORDER',
                data: {
                    id: `#WO-${id}`,
                    title: 'Emergency Repair',
                    priority: 'Urgent',
