    const assignments = await Assignment.find(filter)
      .populate('complaintId') // Get details of the complaint
      .populate('teamId', 'name color') // Get basic team info
      .sort({ createdAt: -1 }); // Newest first

    res.json(assignments);
  } catch (err) {
    next(err);
  }
});

