        // TODO: Vérifier permissions admin/manager
        if (!['admin', 'manager'].includes(req.user.role)) {
            return res.status(403).json({ message: 'Non autorisé' });
        }

        const newSop = new KnowledgeBase({
            title,
            category,
            content,
            tags: tags || [],
