            isActive: true
        });

        await newSop.save();
        logger.info(`Nouvelle SOP créée: ${title}`);

        res.status(201).json({ success: true, data: newSop });
    } catch (error) {
        logger.error('Erreur création SOP:', error);
        res.status(500).json({ success: false, message: 'Erreur serveur' });
    }
});

