/* POST /api/teams */
router.post(
    '/',
    adminOnly,
    [
        body('name').notEmpty(),
        body('color').optional().isHexColor(),
        body('status').optional().isIn(['disponible', 'intervention', 'repos']),
        body('members').optional().isArray(),
        body('leaderId').optional().isMongoId()
    ],
    validator,
