    async (req, res, next) => {
        try {
            const team = await Team.create({
                ...req.body,
                organizationId: (req as any).organizationId
            });

            // Kafka Event
            await eventBus.publish('team-events', 'TEAM_CREATED', {
                teamId: team._id,
                name: team.name,
                status: team.status,
                timestamp: new Date()
            });

