/**
 * @file sshService.ts
 * @description Secure SSH service for remote server administration.
 *              Allows rotating user passwords, auditing active sessions,
 *              and enforcing password policies via node-ssh.
 *              ⚠️ STRICTLY REQUIRES KEY-BASED AUTH (NO PASSWORDS).
 * @module backend/services
 */

import { NodeSSH } from 'node-ssh';
import { AppError } from '../utils/AppError.js';
import { logger } from '../utils/logger.js';

const ssh = new NodeSSH();

/**
 * Configure SSH connection parameters from environment.
 */
const getSSHConfig = () => {
  if (process.env.ENABLE_SSH_MANAGEMENT !== 'true') {
    throw new AppError('Gestion SSH désactivée sur ce serveur', 503, 'SSH_DISABLED');
  }

  return {
    host: process.env.SSH_HOST!,
    username: process.env.SSH_USER!,
    privateKeyPath: process.env.SSH_PRIVATE_KEY_PATH!, // Must be path to ed25519/rsa key
  };
};

/**
 * Helper to execute a command over SSH safely.
 * @param command - Command to execute
 * @param params - Parameters to the command
 * @returns stdout string
 */
const executeSafe = async (command: string, params: string[] = []): Promise<string> => {
  const config = getSSHConfig();
  try {
    await ssh.connect(config);
    const fullCommand = params.length > 0 ? `${command} ${params.join(' ')}` : command;
    const result = await ssh.execCommand(fullCommand);

    if (result.code !== 0 && result.code !== null) {
      logger.error(`[SSH] Command failed (${result.code}): ${result.stderr}`);
      throw new AppError(
        `Échec d'exécution de la commande SSH: ${result.stderr}`,
        500,
        'SSH_EXECUTION_ERROR'
      );
    }

    return result.stdout.trim();
  } catch (err: any) {
    logger.error(`[SSH] Connection/execution error: ${err.message}`);
    throw new AppError(`Erreur de connexion SSH: ${err.message}`, 500, 'SSH_CONNECTION_ERROR');
  } finally {
    ssh.dispose();
  }
};

/**
 * Rotate the password for a target user on the remote server using chpasswd.
 * The remote user running the command must have sudo privileges without a password
 * for the chpasswd command, OR must be root.
 *
 * @param targetUser - User on the remote machine
 * @param newPassword - Plaintext new password
 */
export const rotatePassword = async (targetUser: string, newPassword: string): Promise<void> => {
  logger.warn(`[SSH] Initiating password rotation for user: ${targetUser}`);

  // Clean input to prevent command injection
  if (!/^[a-z_][a-z0-9_-]*[$]?$/.test(targetUser)) {
    throw new AppError("Nom d'utilisateur cible invalide", 400, 'SSH_INVALID_USERNAME');
  }

  // Uses chpasswd over stdin to avoid logging the password in history
  // `echo "user:pass" | sudo chpasswd`
  await executeSafe(`echo "${targetUser}:${newPassword}" | sudo chpasswd`);

  logger.info(`[SSH] ✅ Password rotated successfully for user: ${targetUser}`);
};

/**
 * Audit active SSH sessions on the remote server.
 * Returns the output of the 'w' or 'who' command.
 */
export const getActiveSessions = async (): Promise<string> => {
  logger.info('[SSH] Auditing active sessions');
  // 'w' provides user, tty, from, login@, idle, jcpu, pcpu, what
  const stdout = await executeSafe('w');
  return stdout;
};

/**
 * Enforce password policy on a target user via 'chage'.
 * e.g., forces password expiration in 90 days.
 *
 * @param targetUser - User on the remote machine
 * @param maxDays - Maximum days before password expires
 */
export const enforcePasswordPolicy = async (targetUser: string, maxDays = 90): Promise<void> => {
  if (!/^[a-z_][a-z0-9_-]*[$]?$/.test(targetUser)) {
    throw new AppError("Nom d'utilisateur cible invalide", 400, 'SSH_INVALID_USERNAME');
  }

  logger.info(`[SSH] Enforcing ${maxDays} days expiration policy for user: ${targetUser}`);

  // sudo chage -M 90 user
  await executeSafe('sudo chage', ['-M', maxDays.toString(), targetUser]);
};

/**
 * @file subscriptionService.ts
 * @description Service for managing organization subscriptions,
 *              enforcing limits, and checking feature flags.
 * @module backend/services
 */

import { Membership } from '../models/Membership.js';
import { Organization } from '../models/Organization.js';
import {
  ISubscription,
  PLAN_FEATURES,
  PLAN_MAX_USERS,
  PlanName,
  Subscription,
} from '../models/Subscription.js';
import { SubscriptionLimitError } from '../utils/AppError.js';
import { logger } from '../utils/logger.js';

/**
 * Get or create the default (starter) subscription for an organization.
 */
export const getSubscription = async (orgId: string): Promise<ISubscription> => {
  let sub = await Subscription.findOne({ orgId });

  if (!sub) {
    // Lazy creation of default starter plan for orgs that don't have a record yet
    sub = await Subscription.create({
      orgId,
      plan: 'starter',
      status: 'active',
      maxUsers: PLAN_MAX_USERS.starter,
      features: PLAN_FEATURES.starter,
    });
    logger.info(`[SubscriptionService] Created default starter sub for org ${orgId}`);
  }

  return sub;
};

/**
 * Ensure an organization hasn't exceeded its user limit.
 * Throws SubscriptionLimitError if the limit is reached.
 */
export const enforceUserLimit = async (orgId: string): Promise<void> => {
  const sub = await getSubscription(orgId);

  // Enterprise has Infinity maxUsers
  if (sub.plan === 'enterprise' || sub.maxUsers === Infinity) {
    return;
  }

  const activeMembersCount = await Membership.countDocuments({
    organizationId: orgId,
    status: { $in: ['ACTIVE', 'INVITED'] },
  });

  if (activeMembersCount >= sub.maxUsers) {
    logger.warn(`[SubscriptionService] Org ${orgId} hit user limit (${sub.maxUsers})`);
    throw new SubscriptionLimitError(
      `Limite d'utilisateurs atteinte pour le plan ${sub.plan} (${sub.maxUsers} max). Veuillez mettre à niveau votre abonnement.`
    );
  }
};

/**
 * Check if an organization's plan includes a specific feature.
 */
export const hasFeature = async (orgId: string, feature: string): Promise<boolean> => {
  const sub = await getSubscription(orgId);
  return sub.features.includes(feature) || sub.plan === 'enterprise';
};

/**
 * Handle Webhook data from Stripe to provision or update a subscription.
 */
export const updateFromStripe = async (
  stripeCustomerId: string,
  stripeSubscriptionId: string,
  stripePriceId: string,
  status: string,
  currentPeriodEnd: Date
): Promise<void> => {
  // Map Stripe Price ID back to our PlanName (in a real app, this comes from DB mapping/Stripe metadata)
  let planName: PlanName = 'starter';
  if (stripePriceId === process.env.STRIPE_PRICE_PRO) planName = 'pro';
  if (stripePriceId === process.env.STRIPE_PRICE_ENTERPRISE) planName = 'enterprise';

  const org = await Organization.findOne({ stripeCustomerId });
  if (!org) {
    logger.error(
      `[SubscriptionService] Webhook error: No org found for customer ${stripeCustomerId}`
    );
    return;
  }

  const sub = await Subscription.findOneAndUpdate(
    { orgId: org._id },
    {
      plan: planName,
      status,
      stripeSubscriptionId,
      stripePriceId,
      stripeCustomerId,
      maxUsers: PLAN_MAX_USERS[planName],
      features: PLAN_FEATURES[planName],
      currentPeriodEnd,
    },
    { new: true, upsert: true }
  );

  logger.info(
    `[SubscriptionService] Updated subscription for org ${org._id} to ${planName} (${status})`
  );
};

/**
 * @file tokenService.ts
 * @description Service for issuing, rotating, and revoking JWT token pairs.
 *              Implements:
 *              - Short-lived access tokens (15 min)
 *              - Long-lived refresh tokens (7d), stored as SHA-256 hash in DB
 *              - Refresh token rotation with family-based reuse attack detection
 *              - Phantom token introspection endpoint support
 * @module backend/services
 */

import crypto from 'crypto';
import jwt from 'jsonwebtoken';
import { v4 as uuidv4 } from 'uuid';
import { RefreshToken } from '../models/RefreshToken.js';
import { User } from '../models/User.js';
import {
  AuthAppError,
  NotFoundAppError,
  TokenExpiredAppError,
  TokenInvalidAppError,
} from '../utils/AppError.js';
import { logger } from '../utils/logger.js';

// ──────────────────────────────────────────────────────────────────────────────
// Constants
// ──────────────────────────────────────────────────────────────────────────────

const ACCESS_TOKEN_EXPIRY = process.env.JWT_EXPIRES_IN ?? '15m';
const REFRESH_TOKEN_EXPIRY_DAYS = 7;
const REFRESH_TOKEN_EXPIRY_MS = REFRESH_TOKEN_EXPIRY_DAYS * 24 * 60 * 60 * 1000;

// ──────────────────────────────────────────────────────────────────────────────
// Helpers
// ──────────────────────────────────────────────────────────────────────────────

/**
 * Hash a raw token to the value stored in DB.
 */
const hashToken = (raw: string): string => crypto.createHash('sha256').update(raw).digest('hex');

/**
 * Generate a cryptographically secure opaque refresh token (48 bytes → 96 hex chars).
 */
const generateRawRefreshToken = (): string => crypto.randomBytes(48).toString('hex');

// ──────────────────────────────────────────────────────────────────────────────
// Types
// ──────────────────────────────────────────────────────────────────────────────

export interface TokenPair {
  accessToken: string;
  refreshToken: string;
  expiresIn: number; // seconds until access token expires
}

// ──────────────────────────────────────────────────────────────────────────────
// Public API
// ──────────────────────────────────────────────────────────────────────────────

/**
 * Issue a fresh access + refresh token pair for the given user.
 * Creates a new refresh token family.
 *
 * @param userId - MongoDB ObjectId string of the authenticated user
 * @param role - User role embedded in JWT payload
 * @param email - User email embedded in JWT payload
 * @param ip - Client IP address for audit trail
 */
export const issueTokenPair = async (
  userId: string,
  role: string,
  email: string,
  ip?: string
): Promise<TokenPair> => {
  const accessToken = jwt.sign({ id: userId, role, email }, process.env.JWT_SECRET!, {
    expiresIn: ACCESS_TOKEN_EXPIRY,
  } as jwt.SignOptions);

  const rawRefresh = generateRawRefreshToken();
  const family = uuidv4();

  await RefreshToken.create({
    userId,
    tokenHash: hashToken(rawRefresh),
    family,
    expiresAt: new Date(Date.now() + REFRESH_TOKEN_EXPIRY_MS),
    createdFromIp: ip,
  });

  logger.info(`[TokenService] Issued token pair for user ${userId}`, { family });

  // Parse expiry from access token string to get exact seconds
  const decoded = jwt.decode(accessToken) as { exp: number };
  const expiresIn = decoded.exp - Math.floor(Date.now() / 1000);

  return { accessToken, refreshToken: rawRefresh, expiresIn };
};

/**
 * Rotate a refresh token: validates the current one, revokes it,
 * issues a new pair in the same family.
 *
 * 🔒 If the presented token is already revoked, the ENTIRE family is revoked
 * (reuse attack detection — "refresh token theft" mitigation).
 *
 * @param rawRefreshToken - Raw refresh token string from the client
 * @param ip - Client IP address
 * @throws TokenExpiredAppError | TokenInvalidAppError | AuthAppError
 */
export const rotateRefreshToken = async (
  rawRefreshToken: string,
  ip?: string
): Promise<TokenPair> => {
  const tokenHash = hashToken(rawRefreshToken);
  const record = await RefreshToken.findOne({ tokenHash });

  if (!record) {
    throw new TokenInvalidAppError();
  }

  // Reuse attack: token already revoked → revoke entire family
  if (record.revokedAt) {
    logger.warn(
      `[TokenService] 🚨 Refresh token REUSE detected — revoking family ${record.family}`
    );
    await RefreshToken.updateMany(
      { family: record.family, revokedAt: null },
      { revokedAt: new Date() }
    );
    throw new AuthAppError(
      'Session compromise détectée — reconnectez-vous',
      'AUTH_SESSION_COMPROMISED'
    );
  }

  // Expired
  if (record.expiresAt < new Date()) {
    record.revokedAt = new Date();
    await record.save();
    throw new TokenExpiredAppError();
  }

  // Revoke current token
  record.revokedAt = new Date();
  await record.save();

  // Load user to get latest role/email (in case they changed)
  const user = await User.findById(record.userId).select('role email');
  if (!user) {
    throw new NotFoundAppError('Utilisateur');
  }

  // Issue new pair in the same family
  const rawNew = generateRawRefreshToken();
  await RefreshToken.create({
    userId: record.userId,
    tokenHash: hashToken(rawNew),
    family: record.family,
    expiresAt: new Date(Date.now() + REFRESH_TOKEN_EXPIRY_MS),
    createdFromIp: ip,
  });

  const accessToken = jwt.sign(
    { id: user._id.toString(), role: user.role, email: user.email },
    process.env.JWT_SECRET!,
    { expiresIn: ACCESS_TOKEN_EXPIRY } as jwt.SignOptions
  );

  const decoded = jwt.decode(accessToken) as { exp: number };
  const expiresIn = decoded.exp - Math.floor(Date.now() / 1000);

  logger.info(`[TokenService] Rotated refresh token for user ${record.userId}`, {
    family: record.family,
  });

  return { accessToken, refreshToken: rawNew, expiresIn };
};

/**
 * Revoke a specific refresh token (logout).
 * Does NOT cascade-revoke the family — only the presented token is invalidated.
 */
export const revokeRefreshToken = async (rawRefreshToken: string): Promise<void> => {
  const tokenHash = hashToken(rawRefreshToken);
  const result = await RefreshToken.updateOne(
    { tokenHash, revokedAt: null },
    { revokedAt: new Date() }
  );
  logger.info(`[TokenService] Revoked refresh token (matched: ${result.matchedCount})`);
};

/**
 * Revoke ALL active refresh tokens for a user (logout from all devices).
 */
export const revokeAllUserTokens = async (userId: string): Promise<void> => {
  await RefreshToken.updateMany({ userId, revokedAt: null }, { revokedAt: new Date() });
  logger.info(`[TokenService] Revoked all tokens for user ${userId}`);
};

/**
 * Phantom Token introspection — validates a raw (opaque) refresh token
 * and returns the associated user payload. Used for service-to-service calls.
 *
 * @param rawToken - Opaque refresh token
 * @returns User payload or null if token is invalid/expired/revoked
 */
export const introspectToken = async (
  rawToken: string
): Promise<{ userId: string; role: string; email: string } | null> => {
  const tokenHash = hashToken(rawToken);
  const record = await RefreshToken.findOne({ tokenHash }).populate<{
    userId: { _id: string; role: string; email: string };
  }>('userId', 'role email');

  if (!record || record.revokedAt || record.expiresAt < new Date()) {
    return null;
  }

  const user = record.userId as any;
  return {
    userId: user._id.toString(),
    role: user.role,
    email: user.email,
  };
};

